5245	static void merge_ort_nonrecursive_internal(struct merge_options *opt,
5246						    struct tree *merge_base,
5247						    struct tree *side1,
5248						    struct tree *side2,
5249						    struct merge_result *result)
5250	{
5251		struct object_id working_tree_oid;
5252	
5253		if (opt->subtree_shift) {
5254			side2 = shift_tree_object(opt->repo, side1, side2,
5255						  opt->subtree_shift);
5256			merge_base = shift_tree_object(opt->repo, side1, merge_base,
5257						       opt->subtree_shift);
5258		}
5259	
5260	redo:
5261		trace2_region_enter("merge", "collect_merge_info", opt->repo);
5262		if (collect_merge_info(opt, merge_base, side1, side2) != 0) {
5263			/*
5264			 * TRANSLATORS: The %s arguments are: 1) tree hash of a merge
5265			 * base, and 2-3) the trees for the two trees we're merging.
5266			 */
5267			error(_("collecting merge info failed for trees %s, %s, %s"),
5268			    oid_to_hex(&merge_base->object.oid),
5269			    oid_to_hex(&side1->object.oid),
5270			    oid_to_hex(&side2->object.oid));
5271			result->clean = -1;
5272			move_opt_priv_to_result_priv(opt, result);
5273			return;
5274		}
5275		trace2_region_leave("merge", "collect_merge_info", opt->repo);
5276	
5277		trace2_region_enter("merge", "renames", opt->repo);
5278		result->clean = detect_and_process_renames(opt);
5279		trace2_region_leave("merge", "renames", opt->repo);
5280		if (opt->priv->renames.redo_after_renames == 2) {
5281			trace2_region_enter("merge", "reset_maps", opt->repo);
5282			clear_or_reinit_internal_opts(opt->priv, 1);
5283			trace2_region_leave("merge", "reset_maps", opt->repo);
5284			goto redo;
5285		}
5286	
5287		trace2_region_enter("merge", "process_entries", opt->repo);
5288		if (process_entries(opt, &working_tree_oid) < 0)
5289			result->clean = -1;
5290		trace2_region_leave("merge", "process_entries", opt->repo);
5291	
5292		/* Set return values */
5293		result->path_messages = &opt->priv->conflicts;
5294	
5295		if (result->clean >= 0) {
5296			if (!opt->mergeability_only) {
5297				result->tree = repo_parse_tree_indirect(opt->repo,
5298									&working_tree_oid);
5299				if (!result->tree)
5300					die(_("unable to read tree (%s)"),
5301					    oid_to_hex(&working_tree_oid));
5302			}
5303			/* existence of conflicted entries implies unclean */
5304			result->clean &= strmap_empty(&opt->priv->conflicted);
5305		}
5306		if (!opt->priv->call_depth || result->clean < 0)
5307			move_opt_priv_to_result_priv(opt, result);
5308	}
5309	
5310	/*
5311	 * Originally from merge_recursive_internal(); somewhat adapted, though.
5312	 */
5313	static void merge_ort_internal(struct merge_options *opt,
5314				       const struct commit_list *_merge_bases,
5315				       struct commit *h1,
5316				       struct commit *h2,
5317				       struct merge_result *result)
5318	{
5319		struct commit_list *merge_bases = commit_list_copy(_merge_bases);
5320		struct commit *next;
5321		struct commit *merged_merge_bases;
5322		const char *ancestor_name;
5323		struct strbuf merge_base_abbrev = STRBUF_INIT;
5324	
5325		if (!merge_bases) {
5326			if (repo_get_merge_bases(opt->repo, h1, h2,
5327						 &merge_bases) < 0) {
5328				result->clean = -1;
5329				goto out;
5330			}
5331			/* See merge-ort.h:merge_incore_recursive() declaration NOTE */
5332			merge_bases = commit_list_reverse(merge_bases);
5333		}
5334	
5335		merged_merge_bases = pop_commit(&merge_bases);
5336		if (!merged_merge_bases) {
5337			/* if there is no common ancestor, use an empty tree */
5338			struct tree *tree;
5339	
5340			tree = lookup_tree(opt->repo, opt->repo->hash_algo->empty_tree);
5341			merged_merge_bases = make_virtual_commit(opt->repo, tree,
5342								 "ancestor");
5343			ancestor_name = "empty tree";
5344		} else if (merge_bases) {
5345			ancestor_name = "merged common ancestors";
5346		} else if (opt->ancestor) {
5347			ancestor_name = opt->ancestor;
